    const union = (u: number, v: number): void => {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU !== rootV) {
            if (rank[rootU] > rank[rootV]) {
                parent[rootV] = rootU;
            } else if (rank[rootU] < rank[rootV]) {
                parent[rootU] = rootV;
            } else {
                parent[rootV] = rootU;
                rank[rootU]++;
            }
        }
    };

    // Build the initial network
    for (const [u, v] of connections) {
        union(u, v);
    }

    // Initialize online status and min node in each component
    const online: Set<number> = new Set();
    const componentMin: Map<number, number> = new Map();
    for (let i = 1; i <= c; i++) {
        online.add(i);
        const root = find(i);
        if (!componentMin.has(root) || i < componentMin.get(root)!) {
            componentMin.set(root, i);
        }
    }

    // To efficiently find the min online node in a component, we'll use a map of heaps
    // But since we can't use a heap in TypeScript easily, we'll use a map of sets sorted
    // Instead, we'll track the min node for each component dynamically
    // We'll maintain a map from root to a sorted set of online nodes (but for simplicity, we'll use a set and find min each time)
    const componentOnlineNodes: Map<number, Set<number>> = new Map();
    for (let i = 1; i <= c; i++) {
        const root = find(i);
        if (!componentOnlineNodes.has(root)) {
            componentOnlineNodes.set(root, new Set());
        }
        componentOnlineNodes.get(root)!.add(i);
    }

    const result: number[] = [];

    for (const [type, x] of queries) {
        if (type === 1) {
            const root = find(x);
            if (online.has(x)) {
                result.push(x);
            } else {
                let minNode = Infinity;
                // Iterate through all online nodes in the component to find the min
                if (componentOnlineNodes.has(root)) {
                    for (const node of componentOnlineNodes.get(root)!) {
                        if (online.has(node) && node < minNode) {
                            minNode = node;
                        }
                    }
                }
                if (minNode !== Infinity) {
                    result.push(minNode);
                } else {
                    result.push(-1);
                }
            }
        } else if (type === 2) {
            if (online.has(x)) {
                online.delete(x);
                const root = find(x);
                // No need to update componentOnlineNodes, since offline nodes are still part of the component
            }
        }
    }

    return result;
