        parent[i] = i;
    }

    // Union-Find functions
    const find = (u: number): number => {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    };

    const union = (u: number, v: number): void => {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU !== rootV) {
